// src/TicketHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function TicketHistory({ employee }) {
  const navigate = useNavigate();
  const [ticketExpenses, setTicketExpenses] = useState([]);

  useEffect(() => {
    if (employee?.empld) {
      fetchData();
    }
  }, [employee]);

  const fetchData = async () => {
    try {
      const res = await fetch(
        `${apiBase}/ticket-expenses?empld=${encodeURIComponent(
          employee.empld
        )}`
      );
      const data = await res.json();
      setTicketExpenses(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error("Ticket history fetch error:", err);
      setTicketExpenses([]);
    }
  };

  const handleDownloadPDF = () => {
    window.print();
  };

  const deleteTicket = async (id) => {
    if (!window.confirm("Delete this ticket record?")) return;
    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${id}`, {
        method: "DELETE",
      });
      const data = await res.json();
      if (!data.success && res.status !== 200) {
        alert(data.message || "Failed to delete ticket record");
        return;
      }
      setTicketExpenses((prev) => prev.filter((t) => t.id !== id));
    } catch (err) {
      console.error("Delete ticket error:", err);
      alert("Error deleting ticket record");
    }
  };

  const editTicket = async (row) => {
    const newDate =
      window.prompt(
        "Ticket Date (YYYY-MM-DD):",
        row.ticket_date?.split?.("T")?.[0] || row.ticket_date
      ) || row.ticket_date;
    const newPurpose =
      window.prompt("Purpose:", row.purpose) || row.purpose;
    const newAssigned =
      window.prompt("Assigned To:", row.assigned_to) || row.assigned_to;
    const newAmount =
      window.prompt("Amount:", row.amount) || row.amount;

    try {
      const res = await fetch(`${apiBase}/ticket-expenses/${row.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ticket_date: newDate,
          purpose: newPurpose,
          assigned_to: newAssigned,
          amount: newAmount,
        }),
      });
      const data = await res.json();
      if (!data.success && res.status !== 200) {
        alert(data.message || "Failed to update ticket record");
        return;
      }

      setTicketExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                ticket_date: newDate,
                purpose: newPurpose,
                assigned_to: newAssigned,
                amount: newAmount,
              }
            : t
        )
      );
    } catch (err) {
      console.error("Update ticket error:", err);
      alert("Error updating ticket record");
    }
  };

  if (!employee) {
    return (
      <div style={centerScreen}>
        <div>Employee data not found. Please login again.</div>
      </div>
    );
  }

  return (
    <div
      style={{
        minHeight: "100vh",
        background: lightGreen,
        padding: 20,
        fontFamily: "Segoe UI",
      }}
    >
      <div style={card}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <button
            onClick={() => navigate("/history")}
            style={backBtn}
          >
            ⬅ Back
          </button>
          <h2 style={{ color: green, margin: 0 }}>Ticket Expense History</h2>
        </div>

        <p style={{ fontSize: 13, color: "#555", marginTop: 6 }}>
          Employee: {employee.name} • {employee.empld}
        </p>

        <div style={{ display: "flex", justifyContent: "flex-end", margin: "10px 0" }}>
          <button
            onClick={handleDownloadPDF}
            style={downloadBtn}
          >
            Download PDF
          </button>
        </div>

        <table style={tableStyle}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Assigned To</th>
              <th>Amount</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {ticketExpenses.map((t) => (
              <tr key={t.id}>
                <td>{t.ticket_date?.split?.("T")?.[0] || t.ticket_date}</td>
                <td>{t.purpose}</td>
                <td>{t.assigned_to}</td>
                <td>₹{t.amount}</td>
                <td>
                  <button style={actionBtn} onClick={() => editTicket(t)}>
                    Edit
                  </button>
                  <button
                    style={{ ...actionBtn, borderColor: "#c62828", color: "#c62828" }}
                    onClick={() => deleteTicket(t.id)}
                  >
                    Delete
                  </button>
                </td>
              </tr>
            ))}
            {ticketExpenses.length === 0 && (
              <tr>
                <td colSpan="5" style={{ textAlign: "center", padding: 10 }}>
                  No ticket records found.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

const centerScreen = {
  minHeight: "100vh",
  background: lightGreen,
  display: "flex",
  alignItems: "center",
  justifyContent: "center",
  fontFamily: "Segoe UI",
};

const card = {
  maxWidth: 950,
  margin: "0 auto",
  background: "#ffffff",
  borderRadius: 16,
  padding: 20,
  boxShadow: "0 6px 20px rgba(0,0,0,0.12)",
};

const backBtn = {
  background: "transparent",
  border: "none",
  color: green,
  fontSize: 16,
  cursor: "pointer",
};

const tableStyle = {
  width: "100%",
  borderCollapse: "collapse",
  fontSize: 13,
};

const downloadBtn = {
  padding: "8px 14px",
  borderRadius: 20,
  border: "none",
  background: green,
  color: "#fff",
  fontSize: 13,
  cursor: "pointer",
};

const actionBtn = {
  padding: "3px 8px",
  marginRight: 6,
  borderRadius: 6,
  border: "1px solid " + green,
  background: "#fff",
  fontSize: 11,
  cursor: "pointer",
  color: green,
};
